<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  :root {
    --bg: #0d0f1a;
    --panel: #161a2b;
    --accent: #5eead4;
    --accent2: #f472b6;
    --grid: #1e2338;
    --dead: #12151f;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: radial-gradient(circle at 50% 0%, #1a1f38 0%, var(--bg) 70%);
    color: #e6e9f5;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
  }
  .wrap {
    min-height: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 20px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-weight: 700;
    font-size: 26px;
    letter-spacing: 0.5px;
    background: linear-gradient(90deg, var(--accent), var(--accent2));
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }
  .sub { margin: -12px 0 0; font-size: 13px; color: #8b90a8; }
  #life {
    background: var(--dead);
    border-radius: 12px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.5), 0 0 0 1px rgba(94,234,212,0.15);
    cursor: crosshair;
    touch-action: none;
    image-rendering: pixelated;
  }
  .controls {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    justify-content: center;
    align-items: center;
  }
  button {
    background: var(--panel);
    color: #e6e9f5;
    border: 1px solid rgba(255,255,255,0.08);
    padding: 10px 20px;
    font-size: 14px;
    font-weight: 600;
    border-radius: 8px;
    cursor: pointer;
    transition: transform 0.08s ease, background 0.2s ease, box-shadow 0.2s ease;
  }
  button:hover {
    background: #1f2540;
    box-shadow: 0 4px 16px rgba(94,234,212,0.15);
  }
  button:active { transform: translateY(1px) scale(0.97); }
  #play.running {
    background: linear-gradient(90deg, var(--accent2), #fb7185);
    color: #1a1020;
    border-color: transparent;
  }
  #step { border-color: rgba(94,234,212,0.4); }
  .gen { font-size: 13px; color: #8b90a8; min-width: 90px; text-align: center; }
</style>
</head>
<body>
<div class="wrap">
  <h1>Conway's Game of Life</h1>
  <p class="sub">Click &amp; drag to paint · B3/S23</p>
  <canvas id="life" width="600" height="600"></canvas>
  <div class="controls">
    <button id="step">Step ▸</button>
    <button id="play">Play ▶</button>
    <button id="random">Random ✦</button>
    <button id="clear">Clear ✕</button>
    <span class="gen" id="gen">gen 0</span>
  </div>
</div>
<script>
(function () {
  const W = 60, H = 60;               // grid cells (>= 40)
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const CSS_SIZE = 600;               // >= 400 CSS px
  canvas.style.width = CSS_SIZE + 'px';
  canvas.style.height = CSS_SIZE + 'px';
  const cell = canvas.width / W;      // device px per cell

  let grid = new Uint8Array(W * H);
  let generation = 0;
  const genEl = document.getElementById('gen');

  const idx = (x, y) => y * W + x;
  const inBounds = (x, y) => x >= 0 && y >= 0 && x < W && y < H;

  function get(x, y) {
    if (!inBounds(x, y)) return 0;
    return grid[idx(x, y)];
  }
  function set(x, y, v) {
    if (!inBounds(x, y)) return;
    grid[idx(x, y)] = v ? 1 : 0;
  }

  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let n = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            n += get(x + dx, y + dy);
          }
        }
        const alive = grid[idx(x, y)];
        next[idx(x, y)] = (alive ? (n === 2 || n === 3) : (n === 3)) ? 1 : 0;
      }
    }
    grid = next;
    generation++;
    draw();
  }

  function clear() {
    grid = new Uint8Array(W * H);
    generation = 0;
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) grid[i] = Math.random() < 0.28 ? 1 : 0;
    generation = 0;
    draw();
  }

  function draw() {
    ctx.fillStyle = '#12151f';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    // subtle grid lines
    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 1;
    for (let i = 0; i <= W; i++) {
      ctx.beginPath();
      ctx.moveTo(i * cell + 0.5, 0);
      ctx.lineTo(i * cell + 0.5, canvas.height);
      ctx.stroke();
    }
    for (let j = 0; j <= H; j++) {
      ctx.beginPath();
      ctx.moveTo(0, j * cell + 0.5);
      ctx.lineTo(canvas.width, j * cell + 0.5);
      ctx.stroke();
    }
    // live cells
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          const px = x * cell, py = y * cell;
          const hue = (x * 4 + y * 4 + generation * 6) % 360;
          ctx.fillStyle = `hsl(${hue}, 75%, 62%)`;
          ctx.fillRect(px + 1, py + 1, cell - 2, cell - 2);
        }
      }
    }
    genEl.textContent = 'gen ' + generation;
  }

  // ---- painting ----
  let painting = false, paintVal = 1;
  function cellAt(e) {
    const r = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - r.left) / (r.width / W));
    const y = Math.floor((e.clientY - r.top) / (r.height / H));
    return { x, y };
  }
  canvas.addEventListener('pointerdown', (e) => {
    e.preventDefault();
    const { x, y } = cellAt(e);
    if (!inBounds(x, y)) return;
    paintVal = get(x, y) ? 0 : 1;   // toggle based on first cell
    set(x, y, paintVal);
    painting = true;
    canvas.setPointerCapture(e.pointerId);
    draw();
  });
  canvas.addEventListener('pointermove', (e) => {
    if (!painting) return;
    const { x, y } = cellAt(e);
    set(x, y, paintVal);
    draw();
  });
  const stop = () => { painting = false; };
  canvas.addEventListener('pointerup', stop);
  canvas.addEventListener('pointercancel', stop);

  // ---- controls ----
  let timer = null;
  const playBtn = document.getElementById('play');
  function togglePlay() {
    if (timer) {
      clearInterval(timer);
      timer = null;
      playBtn.textContent = 'Play ▶';
      playBtn.classList.remove('running');
    } else {
      timer = setInterval(step, 90);
      playBtn.textContent = 'Pause ⏸';
      playBtn.classList.add('running');
    }
  }
  document.getElementById('step').addEventListener('click', step);
  playBtn.addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', randomize);
  document.getElementById('clear').addEventListener('click', clear);

  // ---- public API ----
  window.life = {
    w: W, h: H,
    get, set, step, clear,
  };

  // seed something fun (a glider) so it's alive on load
  randomize();
})();
</script>
</body>
</html>
